import{_ as e,c as r,a2 as t,o as i}from"./chunks/framework.R_9q-qV_.js";const h=JSON.parse('{"title":"神秘博士复活时间表","description":"","frontmatter":{"date":"2024-04-08T00:00:00.000Z","tags":["神秘博士"],"categories":["生活"]},"headers":[],"relativePath":"2024/04/神秘博士复活时间表.md","filePath":"2024/04/神秘博士复活时间表.md","lastUpdated":1728661791000}'),l={name:"2024/04/神秘博士复活时间表.md"};function o(s,a,n,d,c,_){return i(),r("div",null,a[0]||(a[0]=[t('<h1 id="神秘博士复活时间表" tabindex="-1">神秘博士复活时间表 <a class="header-anchor" href="#神秘博士复活时间表" aria-label="Permalink to &quot;神秘博士复活时间表&quot;">​</a></h1><ul><li>第一任博士是在老版第三季的《第十行星》中重生的，这个视频资料已经丢失了只能在哔哩哔哩动画上找到重生瞬间。重生原因是因为博士要毁灭赛博人母星，结果能量超载损害了博士的健康从而重生。</li><li>第二任博士是在老版的《战争游戏》一集，重生的资料应该也丢失了，至少我是没找到。是因？为博士要送还战争领主抓来的人类壮丁，而把行踪暴露给了时间领主而被捕，并且除以流放地球和强制重生的处罚</li><li>第三任博士是在《蜘蛛之星》中为了消灭 eight legs，被蓝水晶溢出的致命辐射所伤回到 tardis 后在他曾经的导师帮助下重生。这集没有丢失，可以看到的</li><li>第四任博士是在《杉树》中重生的，为了阻止 master 威胁全宇宙的企图，博士爬上 pharos project 的无线电发射塔断开电缆，由于 master 倾斜了发射器，博士从数百英尺高空跌落地面奄奄一息尾随博士多时并暗中相助的的神秘影子观察者（也有人说这是 clara）附上其身帮助博士开始重生。</li><li>第五任博士是在老版《androzani 的洞穴》中博士和同伴 peri 在 androzani 次级行星的洞穴中无一间接触了蝙蝠产生的剧毒后感染血毒症，最后博士将仅得的唯一一份解药给了 peri，自己濒死而不得不重生。</li><li>第六任博士是在《time and the rani》中，女时间领主 rani 心思 lakertya 行星上用牵引光速击中了经过的 tardis 并迫使其着陆企图利用博士来帮助她控制宇宙历史的进程剧烈的相撞让博士失去意识重生。</li><li>第七任博士是在 1996 年神秘博士大电影中法师被 dalek 处死后要求博士把他的骨灰带回 gallifrey，途中法师扰乱了塔迪斯，使塔迪斯迫降在旧金山的一个帮派战争中。博士出塔迪斯的时候身中三枪，不过并不致命。送医后，因为不熟悉时间领主生理结构的主治医师不听博士劝告乱做手术而致博士死亡，因为麻醉剂的作用，重生被拖延了 n 小时，在停尸间完成重生。（ps：这任博士死的最冤了……活活被戳死……）</li><li>第八任博士是在 2013 年短片《博士之夜》中，为了救地球人（地球人？）cass 逃离时间之战未果而死，后被 karn 姐妹会救活 4 分钟后，选择直面时间之战从而喝下了重生药水，抛弃了博士之名以和平与理性之名重生成了 the warrior（另一种叫法是 the war doctor，或者是 8.5 任）</li><li>the warrior 是在 50 周年特别篇《博士之日》中，听从了 clara 的劝告，放弃毁灭伽里弗雷，并与 10 任，11 任两位博士一同召唤 1 任~12 任博士，13 位博士一起把伽里弗雷冰冻保存后在塔迪斯里重生成第九任</li></ul>',2)]))}const m=e(l,[["render",o]]);export{h as __pageData,m as default};
